module RefModule(q,qbar,clk,rst,d);output reg q;
	output qbar;
	input clk, rst;
	input d;

	assign qbar = ~q;



	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge rst or posedge dbg_halt)
	begin
		if (rst)
			q <= 0;
		else
			q <= d;
	end
endmodule
